   254	/*
   255	** Convert from YYYY-MM-DD HH:MM:SS to julian day.  We always assume
   256	** that the YYYY-MM-DD is according to the Gregorian calendar.
   257	**
   258	** Reference:  Meeus page 61
   259	*/
   260	static void computeJD(DateTime *p){
   261	  int Y, M, D, A, B, X1, X2;
   262	
   263	  if( p->validJD ) return;
   264	  if( p->validYMD ){
   265	    Y = p->Y;
   266	    M = p->M;
   267	    D = p->D;
   268	  }else{
   269	    Y = 2000;  /* If no YMD specified, assume 2000-Jan-01 */
   270	    M = 1;
   271	    D = 1;
   272	  }
   273	  if( Y<-4713 || Y>9999 || p->rawS ){
   274	    datetimeError(p);
   275	    return;
   276	  }
   277	  if( M<=2 ){
   278	    Y--;
   279	    M += 12;
   280	  }
   281	  A = (Y+4800)/100;
   282	  B = 38 - A + (A/4);
   283	  X1 = 36525*(Y+4716)/100;
   284	  X2 = 306001*(M+1)/10000;
   285	  p->iJD = (sqlite3_int64)((X1 + X2 + D + B - 1524.5 ) * 86400000);
   286	  p->validJD = 1;
   287	  if( p->validHMS ){
   288	    p->iJD += p->h*3600000 + p->m*60000 + (sqlite3_int64)(p->s*1000 + 0.5);
   289	    if( p->tz ){
   290	      p->iJD -= p->tz*60000;
   291	      p->validYMD = 0;
   292	      p->validHMS = 0;
   293	      p->tz = 0;
   294	      p->isUtc = 1;
   295	      p->isLocal = 0;
   296	    }
   297	  }
   298	}
