   323	/*
   324	** Parse dates of the form
   325	**
   326	**     YYYY-MM-DD HH:MM:SS.FFF
   327	**     YYYY-MM-DD HH:MM:SS
   328	**     YYYY-MM-DD HH:MM
   329	**     YYYY-MM-DD
   330	**
   331	** Write the result into the DateTime structure and return 0
   332	** on success and 1 if the input string is not a well-formed
   333	** date.
   334	*/
   335	static int parseYyyyMmDd(const char *zDate, DateTime *p){
   336	  int Y, M, D, neg;
   337	
   338	  if( zDate[0]=='-' ){
   339	    zDate++;
   340	    neg = 1;
   341	  }else{
   342	    neg = 0;
   343	  }
   344	  if( getDigits(zDate, "40f-21a-21d", &Y, &M, &D)!=3 ){
   345	    return 1;
   346	  }
   347	  zDate += 10;
   348	  while( sqlite3Isspace(*zDate) || 'T'==*(u8*)zDate ){ zDate++; }
   349	  if( parseHhMmSs(zDate, p)==0 ){
   350	    /* We got the time */
   351	  }else if( *zDate==0 ){
   352	    p->validHMS = 0;
   353	  }else{
   354	    return 1;
   355	  }
   356	  p->validJD = 0;
   357	  p->validYMD = 1;
   358	  p->Y = neg ? -Y : Y;
   359	  p->M = M;
   360	  p->D = D;
   361	  computeFloor(p);
   362	  if( p->tz ){
   363	    computeJD(p);
   364	  }
   365	  return 0;
   366	}
