   389	/*
   390	** Input "r" is a numeric quantity which might be a julian day number,
   391	** or the number of seconds since 1970.  If the value if r is within
   392	** range of a julian day number, install it as such and set validJD.
   393	** If the value is a valid unix timestamp, put it in p->s and set p->rawS.
   394	*/
   395	static void setRawDateNumber(DateTime *p, double r){
   396	  p->s = r;
   397	  p->rawS = 1;
   398	  if( r>=0.0 && r<5373484.5 ){
   399	    p->iJD = (sqlite3_int64)(r*86400000.0 + 0.5);
   400	    p->validJD = 1;
   401	  }
   402	}
